using System.Collections.Generic;
using System.Text.Json;
using HappyPumi.Api.Contracts;

namespace HappyPumi.Api.Tests.Stacks;

/// <summary>
/// Component tests for Tier 2 (ENDPOINTS.md): stack listing, update history, rename, and tags. History
/// is generated by running a real update to completion through the lifecycle endpoints.
/// </summary>
[Collection(HappyPumiCollection.Name)]
public sealed class StackHistoryListingTagsTests(HappyPumiApp app)
{
    private const string Org = "happypumi";
    private const string Project = "webapp";

    private static string StackPath(string s) => $"/api/stacks/{Org}/{Project}/{s}";

    private static async Task<string> NewStack(HttpClient client, string org = Org)
    {
        var stack = $"t2-{Guid.NewGuid():N}";
        using var _ = await client.PostAsJsonAsync(
            $"/api/stacks/{org}/{Project}", new AppCreateStackRequest { StackName = stack });
        return stack;
    }

    // Runs create -> start -> checkpoint -> complete(succeeded) to leave one entry in the stack history.
    private static async Task RunUpdate(HttpClient client, string stack)
    {
        var created = await Post<AppUpdateProgramResponse>(client, $"{StackPath(stack)}/update", new AppUpdateProgramRequest());
        await Post<AppStartUpdateResponse>(client, $"{StackPath(stack)}/update/{created.UpdateId}", new AppStartUpdateRequest());
        using var cp = await client.PatchAsJsonAsync($"{StackPath(stack)}/update/{created.UpdateId}/checkpoint",
            new AppPatchUpdateCheckpointRequest { Version = 3, Deployment = new Dictionary<string, object?>() });
        using var _ = await client.PostAsJsonAsync($"{StackPath(stack)}/update/{created.UpdateId}/complete",
            new AppCompleteUpdateRequest { Status = "succeeded" });
    }

    [Fact]
    public async Task ListUserStacksIncludesCreatedStackFilteredByOrg()
    {
        using var client = app.CreateClient();
        var org = $"org-{Guid.NewGuid():N}";
        var stack = await NewStack(client, org);

        var list = await client.GetFromJsonAsync<AppListStacksResponse>($"/api/user/stacks?organization={org}");

        Assert.NotNull(list);
        Assert.Single(list!.Stacks);
        Assert.Equal(stack, list.Stacks[0].StackName);
        Assert.Equal(org, list.Stacks[0].OrgName);
    }

    [Fact]
    public async Task UpdateHistoryIsRecordedAndReadBack()
    {
        using var client = app.CreateClient();
        var stack = await NewStack(client);
        await RunUpdate(client, stack);

        using var response = await client.GetAsync($"{StackPath(stack)}/updates");
        response.EnsureSuccessStatusCode();
        using var doc = JsonDocument.Parse(await response.Content.ReadAsStringAsync());
        var updates = doc.RootElement.GetProperty("updates");

        Assert.Equal(1, updates.GetArrayLength());
        Assert.Equal("update", updates[0].GetProperty("kind").GetString());
        Assert.Equal("succeeded", updates[0].GetProperty("result").GetString());
        Assert.Equal(1, updates[0].GetProperty("version").GetInt64());
        // Console-extension fields are present alongside the lean CLI fields (same endpoint serves both).
        Assert.Equal("update", updates[0].GetProperty("updateKind").GetProperty("kind").GetString());
        Assert.True(updates[0].TryGetProperty("info", out _));
    }

    [Fact]
    public async Task StackMetadataReportsRealLastUpdateAfterAnUpdate()
    {
        using var client = app.CreateClient();
        var stack = await NewStack(client);

        // Before any update there is no lastUpdate line.
        var before = await client.GetFromJsonAsync<StackMetadata>($"{StackPath(stack)}/metadata");
        Assert.Equal(stack, before!.StackName);
        Assert.Null(before.LastUpdate);

        await RunUpdate(client, stack);

        var after = await client.GetFromJsonAsync<StackMetadata>($"{StackPath(stack)}/metadata");
        Assert.NotNull(after!.LastUpdate);
        Assert.Equal(1, after.LastUpdate!.Version);
        Assert.Equal("succeeded", after.LastUpdate.Result);
        Assert.Equal("update", after.LastUpdate.Kind);
        Assert.Equal(after.LastUpdate.EndTime, after.LastUpdate.Time);
    }

    [Fact]
    public async Task StackMetadataReturns404ForUnknownStack()
    {
        using var client = app.CreateClient();
        using var resp = await client.GetAsync($"{StackPath("missing-" + Guid.NewGuid().ToString("N"))}/metadata");
        Assert.Equal(HttpStatusCode.NotFound, resp.StatusCode);
    }

    [Fact]
    public async Task UpdateHistoryAttributesTheRequestingUser()
    {
        // The "role:<role>:<login>" token convention authenticates as a specific login (PulumiTokenAuthHandler).
        using var alice = app.CreateAuthedClient("role:admin:alice");
        var stack = await NewStack(alice);
        await RunUpdate(alice, stack);

        using var response = await alice.GetAsync($"{StackPath(stack)}/updates");
        response.EnsureSuccessStatusCode();
        using var doc = JsonDocument.Parse(await response.Content.ReadAsStringAsync());
        var by = doc.RootElement.GetProperty("updates")[0].GetProperty("requestedBy");
        Assert.Equal("alice", by.GetProperty("githubLogin").GetString());

        var meta = await alice.GetFromJsonAsync<StackMetadata>($"{StackPath(stack)}/metadata");
        Assert.Equal("alice", meta!.LastUpdate!.RequestedBy!.GithubLogin);
    }

    [Fact]
    public async Task GetLatestStackUpdateReturns404BeforeAnyUpdateThenTheUpdate()
    {
        using var client = app.CreateClient();
        var stack = await NewStack(client);

        using var before = await client.GetAsync($"{StackPath(stack)}/updates/latest");
        Assert.Equal(HttpStatusCode.NotFound, before.StatusCode);

        await RunUpdate(client, stack);

        var latest = await client.GetFromJsonAsync<UpdateInfo>($"{StackPath(stack)}/updates/latest");
        Assert.Equal(1, latest!.Version);
        Assert.NotNull(latest.Info);
    }

    [Fact]
    public async Task GetStackUpdateByVersionReturnsTheEntryOr404()
    {
        using var client = app.CreateClient();
        var stack = await NewStack(client);
        await RunUpdate(client, stack);

        var v1 = await client.GetFromJsonAsync<UpdateInfo>($"{StackPath(stack)}/updates/1");
        Assert.Equal(1, v1!.Version);

        using var missing = await client.GetAsync($"{StackPath(stack)}/updates/99");
        Assert.Equal(HttpStatusCode.NotFound, missing.StatusCode);
    }

    [Fact]
    public async Task RenameMovesTheStack()
    {
        using var client = app.CreateClient();
        var stack = await NewStack(client);
        var renamed = $"{stack}-renamed";

        using var rename = await client.PostAsJsonAsync($"{StackPath(stack)}/rename",
            new AppStackRenameRequest { NewName = renamed, NewProject = Project });
        Assert.Equal(HttpStatusCode.OK, rename.StatusCode);

        using var oldGet = await client.GetAsync(StackPath(stack));
        Assert.Equal(HttpStatusCode.NotFound, oldGet.StatusCode);
        using var newGet = await client.GetAsync(StackPath(renamed));
        Assert.Equal(HttpStatusCode.OK, newGet.StatusCode);
    }

    [Fact]
    public async Task RenameWithNoChangeReturns400()
    {
        using var client = app.CreateClient();
        var stack = await NewStack(client);

        using var rename = await client.PostAsJsonAsync($"{StackPath(stack)}/rename",
            new AppStackRenameRequest { NewName = stack, NewProject = Project });

        Assert.Equal(HttpStatusCode.BadRequest, rename.StatusCode);
    }

    [Fact]
    public async Task AddTagThenReplaceTagsRoundTrips()
    {
        using var client = app.CreateClient();
        var stack = await NewStack(client);

        using var add = await client.PostAsJsonAsync($"{StackPath(stack)}/tags",
            new StackTag { Name = "env", Value = "dev" });
        Assert.Equal(HttpStatusCode.NoContent, add.StatusCode);

        var afterAdd = await client.GetFromJsonAsync<AppStack>(StackPath(stack));
        Assert.Equal("dev", afterAdd!.Tags!["env"]);

        using var replace = await client.PatchAsJsonAsync($"{StackPath(stack)}/tags",
            new Dictionary<string, string> { ["team"] = "platform" });
        Assert.Equal(HttpStatusCode.NoContent, replace.StatusCode);

        var afterReplace = await client.GetFromJsonAsync<AppStack>(StackPath(stack));
        Assert.False(afterReplace!.Tags!.ContainsKey("env")); // wholesale replace removed it
        Assert.Equal("platform", afterReplace.Tags["team"]);
    }

    private static async Task<T> Post<T>(HttpClient client, string url, object body)
    {
        using var response = await client.PostAsJsonAsync(url, body);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<T>())!;
    }
}
